1: //! Zipfian-distributed random number generation.
2: //!
3: //! In the Zipfian distribution a small percentage of candidate
4: //! items have a high probability of being selected, while most items
5: //! have a very low probability of being selected.
6: //! It is commonly understood to model the "80-20" Pareto principle,
7: //! and to be a discreet version of the Pareto distribution,
8: //! and terminology related to both are often used interchangeably.
9: //!
10: //! Zipfian numbers follow an inverse power law, where the 1st item
11: //! is selected with high probability, and subsequent items
12: //! quickly fall off in probability. The rate of the fall off
13: //! is tunable by the _skew_, also called `s`, or `theta`,
14: //! depending on the source.
15: //!
16: //! Reference:
17: //!
18: //! - https://en.wikipedia.org/wiki/Zipf's_law#Formal_definition
19: //!
20: //! Note that it is not actually possible to select a value for
21: //! theta that literally follows the "80-20" rule for arbitrary set sizes;
22: //! the proportion of items that cumulatively make up 80% probability will
23: //! change as the set grows.
24: //! A zipfian generator that can adaptively follow the 80-20 rule is left for future work.
25: //!
26: //! In practice these probabilities often need to be spread across e.g. a
27: //! table's keyspace, which involves some kind of mapping step from index to index.
28: //! Because that mapping is non-trivial to optimize, it is also provided here.
29: //!
30: //! The algorithm here is based on
31: //! "Quickly Generating Billion-Record Synthetic Databases", Jim Gray et al, SIGMOD 1994.
32: //! Per the paper it is adapted from Knuth vol 3.
33: //! This is also the algorithm used by YCSB's ZipfianGenerator.java.
34: //! Note that the code listing in the paper contains obvious errors,
35: //! corrected here and in YCSB.
36: //!
37: //! There are two generators here,
38: //! both of which generate random keys from 0 to a specified maximum.
39: //! In the basic `ZipfianGenerator`, key 0 has the highest probability,
40: //! 1 the next highest, etc.
41: //! The `ZipfianShuffled` generator instead spreads the distribution out
42: //! across the key space as if it were a shuffled deck.
43: //!
44: //! The `ZipfianGenerator` allows the key space to grow,
45: //! but the `ZipfianShuffled` does not - maintaining the illusion of a shuffled
46: //! deck while growing the keyspace involves tradeoffs in the quality
47: //! of the distribution. A previous revision of `ZipfianShuffled` _was_ growable,
48: //! at the cost of not preserving a true Zipfian distribution for the long tail
49: //! of unlikely items. Dig that out of commit history if it's ever needed.
50: //!
51: //! Both should pass a 2-sample Kolmogorov–Smirnov test.
52: 
53: const std = @import("std");
54: const stdx = @import("stdx.zig");
55: const assert = std.debug.assert;
56: const Random = std.Random;
57: const math = std.math;
58: const Snap = stdx.Snap;
59: const module_path = "src/stdx";
60: const snap = Snap.snap_fn(module_path);
61: 
62: /// The default "skew" of the distribution.
63: const theta_default = 0.99; // per YCSB
64: 
65: /// Generates Zipfian-distributed numbers from 0 to a specified maximum.
66: ///
67: /// Many internal variables here are the same is in the paper, which I think
68: /// should reduce confusion if this subject needs to be revisited; the external
69: /// intended to be more understandable to the user and follow TigerStyle.
70: pub const ZipfianGenerator = struct {
71:     theta: f64,
72: 
73:     /// The number of items in the set.
74:     n: u64,
75:     /// The Riemann zeta function calculated up to `n`,
76:     /// aka the "generalized harmonic number" of order `theta` for `n`.
77:     /// This is a pre-calculated factor in the probability of any particular item
78:     /// being selected.
79:     /// It is expensive to calculate for large but useful values of `n`,
80:     /// but can be calculated incrementally as `n` grows.
81:     zetan: f64,
82: 
83:     /// Create a generator from `[0, items)` with `theta` equal to 0.99.
84:     pub fn init(items: u64) ZipfianGenerator {
85:         return ZipfianGenerator.init_theta(items, theta_default);
86:     }
87: 
88:     /// Create a generator from `[0, items)` with given `theta`.
89:     ///
90:     /// `theta` is the "skew" and is usually specified to be greater than 0 and less than 1,
91:     /// with YCSB using 0.99, though values greater than 1 also seem to generate reasonable
92:     /// distributions. `theta = 1` isn't allowed since it does not behave reasonably.
93:     pub fn init_theta(items: u64, theta: f64) ZipfianGenerator {
94:         assert(theta > 0.0);
95:         assert(theta != 1.0);
96:         return ZipfianGenerator{
97:             .theta = theta,
98:             .n = items,
99:             .zetan = zeta(items, theta),
100:         };
101:     }
102: 
103:     /// Note that the variables in this function are mostly named
104:     /// as in the reference paper and do not follow TigerStyle.
105:     pub fn next(self: *const ZipfianGenerator, prng: *stdx.PRNG) u64 {
106:         assert(self.n > 0);
107: 
108:         // Math voodoo, copied from the paper,
109:         // which doesn't explain it, but claims it is from Knuth volume 3.
110: 
111:         // NB: These depend only on zetan and could be cached for a minor speedup.
112:         const alpha = 1.0 / (1.0 - self.theta);
113:         const eta = (1.0 - math.pow(
114:             f64,
115:             2.0 / @as(f64, @floatFromInt(self.n)),
116:             1.0 - self.theta,
117:         )) /
118:             (1.0 - zeta(2.0, self.theta) / self.zetan);
119: 
120:         const u = random_f64(prng);
121:         const uz = u * self.zetan;
122: 
123:         if (uz < 1.0) {
124:             return 0;
125:         }
126: 
127:         if (uz < 1.0 + math.pow(f64, 0.5, self.theta)) {
128:             return 1;
129:         }
130: 
131:         return @as(u64, @intFromFloat(
132:             @as(f64, @floatFromInt(self.n)) *
133:                 math.pow(f64, (eta * u) - eta + 1.0, alpha),
134:         ));
135:     }
136: 
137:     /// Grow the size of the random set.
138:     pub fn grow(self: *ZipfianGenerator, new_items: u64) void {
139:         const items = self.n + new_items;
140:         const zetan_new = zeta_incremental(self.n, new_items, self.zetan, self.theta);
141:         self.* = .{
142:             .theta = self.theta,
143:             .n = items,
144:             .zetan = zetan_new,
145:         };
146:     }
147: };
148: 
149: /// The Riemann zeta function up to `n`,
150: /// aka the "generalized harmonic number" of order 'theta' for `n`.
151: fn zeta(n: u64, theta: f64) f64 {
152:     var i: u64 = 1;
153:     var zeta_sum: f64 = 0.0;
154:     while (i <= n) : (i += 1) {
155:         zeta_sum += math.pow(f64, 1.0 / @as(f64, @floatFromInt(i)), theta);
156:     }
157:     return zeta_sum;
158: }
159: 
160: /// Incremental calculation of zeta.
161: fn zeta_incremental(
162:     n_previous: u64,
163:     n_additional: u64,
164:     zetan_previous: f64,
165:     theta: f64,
166: ) f64 {
167:     const n_new = n_previous + n_additional;
168:     var i = n_previous + 1;
169:     var zeta_sum = zetan_previous;
170:     while (i <= n_new) : (i += 1) {
171:         zeta_sum += math.pow(f64, 1.0 / @as(f64, @floatFromInt(i)), theta);
172:     }
173:     return zeta_sum;
174: }
175: 
176: /// Generates Zipfian-distributed numbers from 0 to maximum,
177: /// but the probabilities of each number are "shuffled",
178: /// not clustered around 0.
179: ///
180: /// This is used to simulate typical data access patterns in
181: /// some keyspace, where a few keys are hot and most are cold.
182: ///
183: /// This behaves as if it maintains a shuffled mapping
184: /// from every index to a different index. Internally, it is implemented
185: /// with a bijective "hash" function (modular‑multiplication permutation)
186: ///     f(i) = (a * i) mod N
187: /// with gcd(a, N) = 1, so every original (Zipfian) index i
188: /// maps to a unique “shuffled” index without collisions.
189: /// Refer to PR #3070 for further details: https://github.com/tigerbeetle/tigerbeetle/pull/3070
190: pub const ZipfianShuffled = struct {
191:     gen: ZipfianGenerator,
192:     a: u64,
193: 
194:     pub fn init(items: u64, prng: *stdx.PRNG) ZipfianShuffled {
195:         return ZipfianShuffled.init_theta(items, theta_default, prng);
196:     }
197: 
198:     pub fn init_theta(items: u64, theta: f64, prng: *stdx.PRNG) ZipfianShuffled {
199:         var zipf = ZipfianShuffled{
200:             .gen = ZipfianGenerator.init_theta(0, theta),
201:             .a = 0, // Correct a is determined in grow.
202:         };
203: 
204:         zipf.choose_shuffle_function(items, prng);
205: 
206:         return zipf;
207:     }
208: 
209:     fn transform(self: *const ZipfianShuffled, zipf_standard: u64) u64 {
210:         return (zipf_standard * self.a) % self.gen.n;
211:     }
212: 
213:     pub fn next(self: *const ZipfianShuffled, prng: *stdx.PRNG) u64 {
214:         const zipf_standard = self.gen.next(prng);
215:         const zipf_shuffled = self.transform(zipf_standard);
216:         return zipf_shuffled;
217:     }
218: 
219:     fn choose_shuffle_function(self: *ZipfianShuffled, new_items: u64, prng: *stdx.PRNG) void {
220:         if (new_items == 0) {
221:             return;
222:         }
223: 
224:         const old_n = self.gen.n;
225:         const new_n = old_n + new_items;
226: 
227:         self.gen.grow(new_items);
228: 
229:         assert(self.gen.n == new_n);
230: 
231:         // We try to find an `a` so that it satisifies gcd(a,N) == 1.
232:         // This allows us to generate a permutation with (a*zipf_standard) mod N.
233:         // This permutation maps one index to another without holes, i.e. is bijective.
234:         self.a = random_coprime(prng, self.gen.n);
235:     }
236: 
237:     fn random_coprime(prng: *stdx.PRNG, n: u64) u64 {
238:         // The bound is arbitrary but should be large enough to find a number that satisifies
239:         // the requirement (see https://en.wikipedia.org/wiki/Euler%27s_totient_function).
240:         for (0..100_000) |_| {
241:             const a = prng.range_inclusive(u64, 1, n);
242:             if (std.math.gcd(a, n) == 1) {
243:                 return a;
244:             }
245:         } else {
246:             @panic("Did not find a random coprime (probabilistic)");
247:         }
248:     }
249: };
