251: /// stdx.PRNG intentionally doesn't support generating floats, to ensure determinism. For
252: /// benchmarking purposes, using floats is OK though, so we fall back to std implementation here.
253: fn random_f64(prng: *stdx.PRNG) f64 {
254:     return std.Random.init(prng, stdx.PRNG.fill).float(f64);
255: }
