26: const statsd_line_size_max = line_size_max: {
27:     // For each type of event, build a payload containing the maximum possible values for that
28:     // event. This is essentially maxInt for unsigned integer payloads, minInt for signed integer
29:     // payloads, and the longest enum tag name for enum payloads.
30:     var events_metric: [std.meta.fieldNames(EventMetric).len]EventMetricAggregate = undefined;
31:     for (&events_metric, std.meta.fields(EventMetric)) |*event_metric, EventMetricInner| {
32:         event_metric.* = .{
33:             .event = @unionInit(
34:                 EventMetric,
35:                 EventMetricInner.name,
36:                 struct_size_max(EventMetricInner.type),
37:             ),
38:             .value = if (@typeInfo(EventMetricAggregate.ValueType).int.signedness == .signed)
39:                 std.math.minInt(EventMetricAggregate.ValueType)
40:             else
41:                 std.math.maxInt(EventMetricAggregate.ValueType),
42:         };
43:     }
44: 
45:     var events_timing: [std.meta.fieldNames(EventTiming).len]EventTimingAggregate = undefined;
46:     for (&events_timing, std.meta.fields(EventTiming)) |*event_timing, EventTimingInner| {
47:         event_timing.* = .{
48:             .event = @unionInit(
49:                 EventTiming,
50:                 EventTimingInner.name,
51:                 struct_size_max(EventTimingInner.type),
52:             ),
53:             .values = .{
54:                 .duration_min = .{ .ns = std.math.maxInt(u64) },
55:                 .duration_max = .{ .ns = std.math.maxInt(u64) },
56:                 .duration_sum = .{ .ns = std.math.maxInt(u64) },
57:                 .count = std.math.maxInt(u64),
58:             },
59:         };
60:     }
61: 
62:     var buffer: [packet_size_max]u8 = undefined;
63:     var buffer_stream = std.io.fixedBufferStream(&buffer);
64:     const buffer_writer = buffer_stream.writer();
65: 
66:     var line_size_max: u32 = 0;
67:     for (events_metric) |event| {
68:         buffer_stream.reset();
69:         format_metric(
70:             buffer_writer,
71:             .{ .metric = .{ .aggregate = event } },
72:             .{ .cluster = std.math.maxInt(u128), .replica = constants.members_max - 1 },
73:         ) catch unreachable;
74:         line_size_max = @max(line_size_max, buffer_stream.getPos() catch unreachable);
75:     }
76:     for (events_timing) |event| {
