129:         state: union(enum) {
130:             /// Store the number of unflushed entries - that is, calls to write() without
131:             /// checkpoint() to ensure we don't ever buffer more than the WAL can hold.
132:             writing: struct { unflushed: u64 },
133: 
134:             /// Keep an opaque pointer to the replica to workaround AOF being ?*AOF in Replica, and
135:             /// @fieldParentPtr being cumbersome with that.
136:             checkpoint: struct {
137:                 replica: *anyopaque,
138:                 replica_callback: *const fn (*anyopaque) void,
139:                 fsync_completion: IO.Completion,
140:             },
141:         } = .{ .writing = .{ .unflushed = 0 } },
142:         size: usize = 0,
143: 
144:         /// Create an AOF in the dir_fd when given a file name. dir_fd must be opened read write
145:         /// (except on Windows). This ensures everything (including the dir) is fsync'd
146:         /// appropriately. Closing dir_fd is the responsibility of the caller, which can be done
147:         /// immediately after .init() finishes.
148:         pub fn init(
149:             io: *IO,
150:             path: []const u8,
151:         ) !AOF {
152:             stdx.maybe(std.fs.path.isAbsolute(path));
153:             assert(std.mem.endsWith(u8, path, ".aof"));
154: 
155:             return AOF{
156:                 .io = io,
157:                 .path = path,
158:                 .fd = try io.aof_blocking_open(path),
159:             };
160:         }
161: 
162:         pub fn close(self: *AOF) void {
163:             assert(self.fd != null);
164: 
165:             self.io.aof_blocking_close(self.fd.?);
166:             self.fd = null;
167:         }
168: 
169:         /// Write a message to disk, with standard blocking IO but using the OS's page cache. The
170:         /// AOF borrows durability from the write ahead log: if the AOF hasn't been flushed, and the
171:         /// machine loses power, the op is guaranteed to still be in the WAL.
172:         pub fn write(self: *AOF, message: *const Message.Prepare) !void {
173:             assert(self.state == .writing);
174:             assert(self.state.writing.unflushed < constants.journal_slot_count);
175: 
176:             var entry: AOFEntry align(constants.sector_size) = undefined;
177:             entry.from_message(
178:                 message,
179:                 &self.last_checksum,
180:             );
181: 
182:             const size_disk = entry.size_disk();
183:             const bytes = std.mem.asBytes(&entry);
184: 
185:             try self.io.aof_blocking_write_all(self.fd.?, bytes[0..size_disk]);
186: 
187:             self.size += size_disk;
188:             self.state.writing.unflushed += 1;
189:         }
190: 
191:         pub fn sync(self: *AOF) void {
192:             assert(self.state == .writing);
193:             assert(self.state.writing.unflushed <= constants.journal_slot_count);
194:             self.state.writing.unflushed = 0;
195:         }
196: 
197:         pub fn checkpoint(
198:             self: *AOF,
199:             replica: *anyopaque,
200:             callback: *const fn (*anyopaque) void,
201:         ) void {
202:             assert(self.state == .writing);
203:             assert(self.state.writing.unflushed <= constants.journal_slot_count);
204: 
205:             self.state = .{
206:                 .checkpoint = .{
207:                     .replica = replica,
208:                     .fsync_completion = undefined,
209:                     .replica_callback = callback,
210:                 },
211:             };
212: 
213:             self.io.fsync(
214:                 *AOF,
215:                 self,
216:                 on_fsync,
217:                 &self.state.checkpoint.fsync_completion,
218:                 self.fd.?,
219:             );
220:         }

