299:     pub const Flags = packed struct {
300:         /// Normally release upgrades are allowed to skip to the latest. If a corresponding release
301:         /// is set to true here, it must be visited on the way to the newest release.
302:         visit: bool,
303: 
304:         /// If this binary has debug info attached.
305:         debug: bool,
306: 
307:         padding: u6 = 0,
308: 
309:         comptime {
310:             assert(@sizeOf(Flags) == 1);
311:             assert(@bitSizeOf(Flags) == @sizeOf(Flags) * 8);
