324:         count: u32 = 0,
325: 
326:         releases: [past_releases_max]u32 = @splat(0),
327:         checksums: [past_releases_max]u128 = @splat(0),
328: 
329:         /// Offsets are relative to the start of the body (`.tb_mvb`) offset.
330:         offsets: [past_releases_max]u32 = @splat(0),
331: 
332:         sizes: [past_releases_max]u32 = @splat(0),
333: 
334:         flags: [past_releases_max]Flags = @splat(.{ .visit = false, .debug = false }),
335:         flags_padding: [1]u8 = @splat(0),
336: 
337:         // Extra metadata. Not used by any current upgrade processes directly, but useful to know:
338:         git_commits: [past_releases_max][20]u8 = @splat(@splat(0)),
339:         release_client_mins: [past_releases_max]u32 = @splat(0),
340: 
341:         pub fn add(self: *PastReleases, next: struct {
342:             release: u32,
343:             checksum: u128,
344:             size: u32,
345:             flags: Flags,
346:             git_commit: [20]u8,
347:             release_client_min: u32,
348:         }) void {
349:             assert(next.release != 0);
350:             assert(next.checksum != 0);
351:             assert(next.size != 0);
352:             assert(next.release_client_min != 0);
353: 
354:             assert(self.count < past_releases_max);
355:             const index = self.count;
356: 
357:             if (index > 0) {
358:                 assert(self.releases[index - 1] < next.release);
359:             }
360: 
361:             const offset = if (index > 0)
362:                 self.offsets[index - 1] + self.sizes[index - 1]
363:             else
364:                 0;
365: 
366:             self.releases[index] = next.release;
367:             self.checksums[index] = next.checksum;
368:             self.offsets[index] = offset;
369:             self.sizes[index] = next.size;
370:             self.flags[index] = next.flags;
371:             self.git_commits[index] = next.git_commit;
372:             self.release_client_mins[index] = next.release_client_min;
373:             self.count += 1;
374:         }
