376:         pub fn verify(self: *const PastReleases) !void {
377:             if (self.count > past_releases_max) return error.InvalidPastReleases;
378:             if (self.count == 0) return error.InvalidPastReleases;
379: 
380:             if (!stdx.zeroed(std.mem.sliceAsBytes(self.releases[self.count..])) or
381:                 !stdx.zeroed(std.mem.sliceAsBytes(self.checksums[self.count..])) or
382:                 !stdx.zeroed(std.mem.sliceAsBytes(self.offsets[self.count..])) or
383:                 !stdx.zeroed(std.mem.sliceAsBytes(self.sizes[self.count..])) or
384:                 !stdx.zeroed(std.mem.sliceAsBytes(self.flags[self.count..])) or
385:                 !stdx.zeroed(&self.flags_padding) or
386:                 !stdx.zeroed(std.mem.sliceAsBytes(self.git_commits[self.count..])) or
387:                 !stdx.zeroed(std.mem.sliceAsBytes(self.release_client_mins[self.count..])))
388:             {
389:                 return error.InvalidPastReleases;
390:             }
391: 
392:             const releases = self.releases[0..self.count];
393:             const offsets = self.offsets[0..self.count];
394:             const sizes = self.sizes[0..self.count];
395:             const flags = self.flags[0..self.count];
396:             const git_commits = self.git_commits[0..self.count];
397:             const release_client_mins = self.release_client_mins[0..self.count];
398: 
399:             for (releases) |v| if (v == 0) return error.InvalidPastReleases;
400:             if (!std.sort.isSorted(u32, releases, {}, std.sort.asc(u32))) {
401:                 return error.InvalidPastReleases;
402:             }
403: 
404:             if (offsets[0] != 0) return error.InvalidPastReleases;
405:             for (offsets[1..], 1..) |offset, i| {
406:                 const calculated_offset = blk: {
407:                     var calculated_offset: u32 = 0;
408:                     for (sizes[0..i]) |size| {
409:                         calculated_offset += size;
410:                     }
411:                     break :blk calculated_offset;
412:                 };
413:                 if (offset == 0) return error.InvalidPastReleases;
414:                 if (offset != calculated_offset) return error.InvalidPastReleases;
415:             }
416: 
417:             for (sizes) |s| if (s == 0) return error.InvalidPastReleases;
418:             for (flags) |f| if (f.padding != 0) return error.InvalidPastReleases;
419:             for (git_commits) |g| if (stdx.zeroed(&g)) return error.InvalidPastReleases;
420:

420: 
421:             for (release_client_mins) |v| if (v == 0) return error.InvalidPastReleases;
422:             if (!std.sort.isSorted(u32, release_client_mins, {}, std.sort.asc(u32))) {
423:                 return error.InvalidPastReleases;
424:             }
425:         }
