427:         /// Used by the build process to verify that the inner checksums are correct. Skipped during
428:         /// runtime, as the outer checksum includes them all. This same method can't be implemented
429:         /// for current_release, as that would require `objcopy` at runtime to split the pieces out.
430:         pub fn verify_checksums(self: *const PastReleases, body: []const u8) !void {
431:             for (
432:                 self.checksums[0..self.count],
433:                 self.offsets[0..self.count],
434:                 self.sizes[0..self.count],
435:             ) |checksum_expected, offset, size| {
436:                 const checksum_calculated = checksum.checksum(body[offset..][0..size]);
437:                 if (checksum_calculated != checksum_expected) {
438:                     return error.PastReleaseChecksumMismatch;
439:                 }
440:             }
441:         }
442:     };
443: 
444:     /// Covers MultiversionHeader[@sizeOf(u128)..].
445:     checksum_header: u128 = undefined,
446: 
447:     /// The AEGIS128L checksum of the binary, if the header (`.tb_mvh`) section were zeroed out.
448:     /// Used to validate that the binary itself is not corrupt. Putting this in requires a bit
449:     /// of trickery:
450:     /// * inject a zero `.tb_mvh` section of the correct size,
451:     /// * compute the hash,
452:     /// * update the section with the correct data.
453:     /// Used to ensure we don't try and exec into a corrupt binary.
454:     checksum_binary_without_header: u128 = 0,
455: 
456:     /// The AEGIS128L checksum of the direct output of `zig build`, for the current_release, before
457:     /// any objcopy or build magic has been performed.
458:     /// Used when extracting the latest binary from a now-past release during the build process.
459:     /// Instead of having to rebuild from source, objcopy is used to remove the multiversion
460:     /// sections, which is then compared to this checksum to ensure the output is identical.
461:     current_checksum: u128,
462: 
463:     /// Track the schema of the header. It's possible to completely change the schema - past this
464:     /// point - while maintaining an upgrade path by having a transitional release:
465:     /// * 0.15.4 uses schema version 1,
466:     /// * 0.15.5 uses schema version 1/2,
467:     /// * 0.15.6 uses schema version 2.
468:     ///
469:     /// Then, it's possible to have 2 multiversion releases, one with {0.15.4, 0.15.5} and one with
470:     /// {0.15.5, 0.15.6}, that allow an upgrade path with 2 steps.
471:     schema_version: u32 = 1,
472:     vsr_releases_max: u32 = constants.vsr_releases_max,
473: 
474:     /// The current release is executed differently to past releases embedded in the body, so store
475:     /// it separately. See exec_current vs exec_release.
476:     current_release: u32,
477: 
478:     current_flags: Flags,
479:     current_flags_padding: [3]u8 = @splat(0),
480: 
481:     past: PastReleases = .{},
482:     past_padding: [16]u8 = @splat(0),
483: 
484:     current_git_commit: [20]u8,
485:     current_release_client_min: u32,
486: 
487:     /// Reserved space for future use. This is special: unlike the rest of the *_padding fields,
488:     /// which are required to be zeroed, this is not. This allows adding whole new fields in a
489:     /// backwards compatible way, while preventing the temptation of changing the meaning of
490:     /// existing fields without bumping the schema version entirely.
491:     reserved: [4744]u8 = @splat(0),
492: 
493:     /// Parses an instance from a slice of bytes and validates its checksum. Returns a copy.
494:     pub fn init_from_bytes(bytes: *const [@sizeOf(MultiversionHeader)]u8) !MultiversionHeader {
495:         const self = std.mem.bytesAsValue(MultiversionHeader, bytes).*;
496:         try self.verify();
497: 
498:         return self;
499:     }
