501:     pub fn verify(self: *const MultiversionHeader) !void {
502:         const checksum_calculated = self.calculate_header_checksum();
503: 
504:         if (checksum_calculated != self.checksum_header) return error.ChecksumMismatch;
505:         if (self.schema_version != 1) return error.InvalidSchemaVersion;
506:         if (self.vsr_releases_max != constants.vsr_releases_max) return error.InvalidVSRReleaseMax;
507:         if (self.current_flags.padding != 0) return error.InvalidCurrentFlags;
508:         if (!stdx.zeroed(&self.current_flags_padding)) return error.InvalidCurrentFlags;
509:         if (!self.current_flags.visit) return error.InvalidCurrentFlags;
510:         if (self.current_release == 0) return error.InvalidCurrentRelease;
511: 
512:         // current_git_commit and current_release_client_min were added after 0.15.4.
513:         if (self.current_release > (try Release.parse("0.15.4")).value) {
514:             if (stdx.zeroed(&self.current_git_commit)) return error.InvalidCurrentRelease;
515:             if (self.current_release_client_min == 0) return error.InvalidCurrentRelease;
516:         } else {
517:             if (!stdx.zeroed(&self.current_git_commit)) return error.InvalidCurrentRelease;
518:             if (self.current_release_client_min != 0) return error.InvalidCurrentRelease;
519:         }
520: 
521:         stdx.maybe(stdx.zeroed(&self.reserved));
522: 
523:         try self.past.verify();
524:         if (!stdx.zeroed(&self.past_padding)) return error.InvalidPastPadding;
525: 
526:         const past_release_newest = self.past.releases[self.past.count - 1];
527:         if (past_release_newest >= self.current_release) return error.PastReleaseNewerThanCurrent;
528:     }
