222:         fn on_fsync(self: *AOF, completion: *IO.Completion, result: IO.FsyncError!void) void {
223:             _ = completion;
224:             _ = result catch @panic("aof fsync failure");
225: 
226:             assert(self.state == .checkpoint);
227:             const replica = self.state.checkpoint.replica;
228:             const replica_callback = self.state.checkpoint.replica_callback;
229:             self.state = .{ .writing = .{ .unflushed = 0 } };
230: 
231:             const stat_file = self.io.aof_blocking_stat(self.path) catch |err| switch (err) {
232:                 error.FileNotFound => blk: {
233:                     log.info("{s} not found; creating", .{self.path});
234:                     self.close();
235:                     assert(self.fd == null);
236:                     self.fd = self.io.aof_blocking_open(self.path) catch |e| {
237:                         std.debug.panic("failed to reopen {s} after rotate: {}", .{ self.path, e });
238:                     };
239: 
240:                     break :blk self.io.aof_blocking_stat(self.path) catch |e| {
241:                         log.warn("failed to stat aof ({s}): {}", .{ self.path, e });
242:                         break :blk null;
243:                     };
244:                 },
245:                 else => blk: {
246:                     log.warn("failed to stat aof ({s}): {}", .{ self.path, err });
247:                     break :blk null;
248:                 },
249:             };
250: 
251:             const stat_fd = self.io.aof_blocking_fstat(self.fd.?) catch |err| blk: {
252:                 log.warn("failed to fstat aof ({s}): {}", .{ self.path, err });
253:                 break :blk null;
254:             };
255: 
256:             // AOF change detection relies on detecting the file being removed, and *it* will
257:             // recreate it. It is an error for the operator to try and create file externally
258:             // (eg, touch tigerbeetle.aof).
259:             //
260:             // Warn the operator strongly if this happens.
261:             if (stat_fd != null and stat_file != null and stat_fd.?.inode != stat_file.?.inode) {
262:                 log.err("AOF inode mismatch detected - the AOF file path is not the same as " ++
263:                     "the open file descriptor being written to.", .{});
264:                 log.err(
265:                     "Move {s} out the way, and let tigerbeetle recreate the AOF.",
266:                     .{self.path},
267:                 );
268:             }
269: 
270:             replica_callback(replica);
271:         }
