273:         pub fn validate(self: *AOF, allocator: std.mem.Allocator, last_checksum: ?u128) !void {
274:             var validation_target: AOFEntry = undefined;
275: 
276:             var validation_checksums = std.AutoHashMap(u128, void).init(allocator);
277:             defer validation_checksums.deinit();
278: 
279:             var it = Iterator{
280:                 .file_descriptor = self.fd.?,
281:                 .io = self.io,
282:                 .size = self.size,
283:             };
284: 
285:             // The iterator only does simple chain validation, but we can have backtracking
286:             // or duplicates, and still have a valid AOF. Handle this by keeping track of
287:             // every checksum we've seen so far, and considering it OK as long as we've seen
288:             // a parent.
289:             it.validate_chain = false;
290: 
291:             var last_entry: ?*AOFEntry = null;
292: 
293:             while (try it.next(&validation_target)) |entry| {
294:                 const header = entry.header();
295: 
296:                 if (entry.header().op == 1) {
297:                     // For op=1, put its parent in our list of seen checksums too.
298:                     // This handles the case where it gets replayed, but we don't record
299:                     // op=0 so the assert below would fail.
300:                     // It's needed for simulator validation only (aof merge uses a
301:                     // different method to walk down AOF entries).
302:                     try validation_checksums.put(header.parent, {});
303:                 } else {
304:                     // (Null due to state sync skipping commits.)
305:                     stdx.maybe(validation_checksums.get(header.parent) == null);
306:                 }
307: 
308:                 try validation_checksums.put(header.checksum, {});
309: 
310:                 last_entry = entry;
311:             }
312: 
313:             if (last_checksum) |checksum| {
314:                 if (last_entry.?.header().checksum != checksum) {
315:                     return error.ChecksumMismatch;
316:                 }
317:                 log.info("validated all aof entries. last entry checksum {x:0>32} matches " ++
318:                     " supplied {x:0>32}", .{ last_entry.?.header().checksum, checksum });
319:             } else {
320:                 log.info("validated present aof entries.", .{});

320:                 log.info("validated present aof entries.", .{});
321:             }
322:         }
