355:                 client.* = try Client.init(
356:                     allocator,
357:                     time,
358:                     message_pool,
359:                     .{
360:                         // Use a deterministic client id, so that replaying the same AOF against
361:                         // different new clusters yields physically identical data files.
362:                         // (It must be based on release so that clusters which have upgraded at some
363:                         // point will need a separate "aof recover" invocation for each release.)
364:                         .id = constants.config.process.release.value,
365:                         .cluster = cluster,
366:                         .replica_count = @intCast(addresses.len),
