401:                 while (try iterator.next(&target)) |entry| {
402:                     // Skip replaying reserved messages and messages not marked for playback.
403:                     const header = entry.header();
404:                     assert(header.cluster == self.client.cluster);
405:                     if (!ReplayClient.replay_message(header)) continue;
