407:                     const message = self.client.get_message().build(.request);
408:                     errdefer self.client.release_message(message.base());
409: 
410:                     assert(self.inflight_message == null);
411:                     self.inflight_message = message;
412: 
413:                     entry.to_message(message.base().build(.prepare));
414: 
415:                     message.header.* = .{
416:                         .client = self.client.id,
417:                         .cluster = self.client.cluster,
418:                         .command = .request,
419:                         .operation = header.operation,
