430:                     self.client.raw_request(

450:                 switch (state_machine_operation) {
451:                     .create_accounts,
452:                     .create_transfers,
453:                     .deprecated_create_accounts_sparse,
454:                     .deprecated_create_transfers_sparse,
455:                     .deprecated_create_accounts_unbatched,
456:                     .deprecated_create_transfers_unbatched,
